<?php
class AuthController { public function login(): void { if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){ Security::verifyCsrf(); if(!Security::rateLimit('login',8,300)) exit('Too many attempts'); $u=(new User())->findByEmail(Validator::email($_POST['email']??'')); if($u && password_verify($_POST['password']??'', $u['password_hash']) && $u['status']==='active'){ session_regenerate_id(true); $_SESSION['user_id']=$u['id']; $_SESSION['role']=$u['role']; Audit::log('login'); header('Location: /'); exit; } Audit::log('failed_login',['email'=>$_POST['email']??'']); $error='Invalid credentials'; } View::render('auth/login',['title'=>'Login','error'=>$error??null]); }
 public function register(): void { if(($_SERVER['REQUEST_METHOD']??'GET')==='POST'){ Security::verifyCsrf(); $id=(new User())->create(Validator::str($_POST['username']??'',3,40),Validator::email($_POST['email']??''),Validator::str($_POST['password']??'',8,200)); Audit::log('register',['user_id'=>$id]); header('Location: /login'); exit; } View::render('auth/register',['title'=>'Register']); }
 public function logout(): void { Security::verifyCsrf(); Audit::log('logout'); session_destroy(); header('Location: /'); }}
